import{_ as e,c as t,o as a,ag as n}from"./chunks/framework.Z1I7rvLq.js";const h=JSON.parse('{"title":"Mint/LemonMint官方文档","description":"","frontmatter":{"title":"Mint/LemonMint官方文档"},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),l={name:"index.md"};function o(r,i,s,m,d,p){return a(),t("div",null,i[0]||(i[0]=[n(`<h1 id="mint-lemonmint官方文档" tabindex="-1">Mint/LemonMint官方文档 <a class="header-anchor" href="#mint-lemonmint官方文档" aria-label="Permalink to &quot;Mint/LemonMint官方文档&quot;">​</a></h1><blockquote><p>该文档暂未完成，暂时只有一些词条</p></blockquote><p>这是Mint/LemonMint的官方文档，Mint是一个基于Folia的高性能服务端，专注于修复特性与优化性能，LemonMint前身是Mint-radical现是基于Mint的服务端，其为了在Mint的基础上添加新的特性以及让大部分Bukkit老插件兼容，同时也有一些之前因过于激进被细菌pass掉的特性（现在估计删完了...）</p><h2 id="mint服务端的特性" tabindex="-1">Mint服务端的特性 <a class="header-anchor" href="#mint服务端的特性" aria-label="Permalink to &quot;Mint服务端的特性&quot;">​</a></h2><ul><li>可配置的原版特性</li><li>Tpsbar、Membar、Regionbar、Networkbar监控</li><li>各种Fork的优化</li><li>对单线程区域性能的优化</li><li>支持线性区域文件格式</li><li>修复上游的错误</li><li>以及提高稳定性</li><li>集成 Pufferfish 的 Sentry，轻松详细追踪服务器的所有报错</li><li>NetworkAnalyser 数据包分析</li></ul><h2 id="目前相对于mint-lemonmint独有的特性" tabindex="-1">目前相对于Mint，LemonMint独有的特性 <a class="header-anchor" href="#目前相对于mint-lemonmint独有的特性" aria-label="Permalink to &quot;目前相对于Mint，LemonMint独有的特性&quot;">​</a></h2><ul><li>Bukkit Teleport的调用正常化（不完全）</li><li>Bukkit Scoreboard API和原本Scoreboard命令的正常化（但是Bukkit API创建的Scoreboard并不受原版的Scoreboard指令控制）</li><li>从Purpur搬过来的6格末影箱（某位用户提起的，其实在1.21.5还是1.21.7就开始提的，1.21.8才正式搬过来）</li><li>对于Bukkit Scheduler API的简单恢复（并不代表全部恢复）</li><li>Lua插件机制（在测试，为<a href="https://github.com/MenthaMC/LemonMint/tree/dev/1.21.8-new-plugin-system" target="_blank" rel="noreferrer">dev/1.21.8-new-plugin-system</a>分支独有）</li></ul><h2 id="更多信息" tabindex="-1">更多信息 <a class="header-anchor" href="#更多信息" aria-label="Permalink to &quot;更多信息&quot;">​</a></h2><ul><li>关于配置的更多信息可以看本网站，其他的可以去仓库自行了解：<a href="https://github.com/ManthaMC" target="_blank" rel="noreferrer">GitHub</a></li></ul><h2 id="文件结构" tabindex="-1">文件结构 <a class="header-anchor" href="#文件结构" aria-label="Permalink to &quot;文件结构&quot;">​</a></h2><p>Mint/LemonMint 的文件结构与Bukkit、Folia、Paper等服务端相似，相比他们，我们多了一个<code>mint</code>文件夹，专门存放面对服务端的配置。</p><p>Mint 文件夹文件结构</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mint/</span></span>
<span class="line"><span>└── mint_global.toml</span></span></code></pre></div><p>其中的mint_global.toml 是存放绝大多数配置的文件，其格式是toml。</p>`,14)]))}const u=e(l,[["render",o]]);export{h as __pageData,u as default};
